// Datos del remitente
const emailMeta   = $('HTTP Request remitente').item.json;
const fromAddress = emailMeta.from?.emailAddress?.address || '';
const fromName    = emailMeta.from?.emailAddress?.name || fromAddress;
const subject     = emailMeta.subject || '';
const emailId     = emailMeta.id || '';

// Adjuntos
const adjuntosData = $('HTTP Request adjunto').item.json;
const adjuntos     = adjuntosData.value || [];

let xlsxKey  = null;
let xlsxName = null;
const pdfItems   = [];
const binaryData = {};

for (const adj of adjuntos) {
  const name     = (adj.name || '').toLowerCase();
  const mimeType = adj.contentType || '';
  const b64      = adj.contentBytes || '';

  if (name.endsWith('.xlsx') || mimeType.includes('spreadsheetml')) {
    if (!xlsxKey) {
      xlsxKey  = 'xlsx_file';
      xlsxName = adj.name;
      binaryData['xlsx_file'] = {
        data:          b64,
        mimeType:      mimeType,
        fileName:      adj.name,
        fileExtension: 'xlsx'
      };
    }
  } else if (name.endsWith('.pdf') || mimeType.includes('pdf')) {
    const pdfKey = `pdf_${pdfItems.length}`;
    pdfItems.push({ key: pdfKey, name: adj.name });
    binaryData[pdfKey] = {
      data:          b64,
      mimeType:      mimeType,
      fileName:      adj.name,
      fileExtension: 'pdf'
    };
  }
}


const now  = new Date();
const yyyy = String(now.getFullYear());
const mm   = String(now.getMonth() + 1).padStart(2, '0');

return {
  json: {
    emailId,
    fromAddress,
    fromName,
    subject,
    xlsxKey,
    xlsxName,
    pdfKeys:          pdfItems,
    hasPdfs:          pdfItems.length > 0,
    yyyy,
    mm,
    receivedDateTime: $('Outlook - Recibir Correo').item.json.receivedDateTime || '', 
    fechaCargue:      now.toISOString().split('T')[0]
  },
  binary: binaryData
};

const items  = $input.all();
const item   = items[0];
const json   = item?.json   || {};
const binary = item?.binary || {};

const { pdfKeys, yyyy, mm, receivedDateTime } = json;
const fromAddress = json.fromAddress 
                 || $('HTTP Request remitente').item.json?.from?.emailAddress?.address 
                 || '';

if (!pdfKeys || pdfKeys.length === 0) return [];

// Usuario: solo la parte antes del @
const usuario = (fromAddress || '').split('@')[0].toLowerCase();

// Fecha y hora del correo
const fechaCorreo = receivedDateTime ? new Date(receivedDateTime) : new Date();

const AAAA = fechaCorreo.getFullYear().toString();
const MM   = String(fechaCorreo.getMonth() + 1).padStart(2, '0');
const DD   = String(fechaCorreo.getDate()).padStart(2, '0');
const HHMM = String(fechaCorreo.getHours()).padStart(2, '0') +
             String(fechaCorreo.getMinutes()).padStart(2, '0');

const results = [];

for (const pdf of pdfKeys) {
  const binData = binary[pdf.key];
  if (!binData) continue;

  // Formato: 2026_02_27_1808_directortic_NombreOriginal.pdf
  const nuevoNombre = `${AAAA}_${MM}_${DD}_${HHMM}_${usuario}_${pdf.name}`;

  results.push({
    json: {
      fromAddress,
      yyyy,
      mm,
      pdfName:      nuevoNombre,
      onedrivePath: `/Cohortes/SaludMental/Documentos/${yyyy}-${mm}/${nuevoNombre}`
    },
    binary: {
      data: binData
    }
  });
}

return results;

const JSZip = require('jszip');
const items  = $input.all();
const item   = items[0];
const json   = item?.json   || {};
const binary = item?.binary || {};

const { validRows, invalidRows, yyyy, mm, fechaCargue, xlsxName, fromAddress, xlsxKey } = json;

if (!validRows || validRows.length === 0) {
  return [{ json: { ...json, outputName: null }, binary }];
}

const binEntry = binary[xlsxKey]
              || $('Validar Token y Estructura').item?.binary?.[xlsxKey]
              || null;

if (!binEntry?.data) {
  return [{ json: { ...json, outputName: null, motivoError: 'Binario no disponible' }, binary }];
}

const filasInvalidas = new Set((invalidRows || []).map(r => r.fila));

const buf = Buffer.from(binEntry.data, 'base64');
const zip  = await JSZip.loadAsync(buf);

const workbookXml = await zip.file('xl/workbook.xml').async('string');
const sheetMatch  = workbookXml.match(/name="SEGUIMIENTO_SM"[^>]*r:id="(rId\d+)"/);
const rId         = sheetMatch?.[1];
const relsXml     = await zip.file('xl/_rels/workbook.xml.rels').async('string');
const relMatch    = relsXml.match(new RegExp(`Id="${rId}"[^>]*Target="([^"]+)"`));
const sheetPath   = `xl/${relMatch?.[1]}`;

let sheetXml = await zip.file(sheetPath).async('string');

// Extraer TODAS las filas del XML
const allRows = [...sheetXml.matchAll(/<row\b[^>]*\sr="(\d+)"[^>]*>[\s\S]*?<\/row>/g)];

const DATA_START = 4; // fila 4 es donde empiezan los datos (1-based)

// Separar cabeceras y datos
const headerRows = allRows.filter(m => parseInt(m[1]) < DATA_START);
const dataRows   = allRows.filter(m => parseInt(m[1]) >= DATA_START);

// Detectar estilos alternados: capturar s="N" de cada celda en fila 4 y 5
const getStyleMap = (rowXml) => {
  const map = {};
  const cells = [...rowXml.matchAll(/<c\s+r="([A-Z]+)\d+"([^>]*)>/g)];
  for (const cell of cells) {
    const col   = cell[1];
    const attrs = cell[2];
    const sMatch = attrs.match(/\bs="(\d+)"/);
    map[col] = sMatch ? sMatch[1] : null;
  }
  return map;
};

const styleOdd  = dataRows[0] ? getStyleMap(dataRows[0][0]) : {}; // fila 4 → impar
const styleEven = dataRows[1] ? getStyleMap(dataRows[1][0]) : {}; // fila 5 → par

// Filtrar filas inválidas
const validDataRows = dataRows.filter(m => !filasInvalidas.has(parseInt(m[1])));

// Renumerar y corregir estilos alternados
const fixedRows = validDataRows.map((match, idx) => {
  const newRowNum = DATA_START + idx;
  const esImpar   = idx % 2 === 0; // 0,2,4... → impar visual
  const styleMap  = esImpar ? styleOdd : styleEven;

  let rowXml = match[0];

  // Renumerar el atributo r de la fila
  rowXml = rowXml.replace(/(<row\b[^>]*\s)r="\d+"/, `$1r="${newRowNum}"`);

  // Renumerar referencias de celdas (A4 → A_newRowNum, etc.)
  rowXml = rowXml.replace(/(<c\s+r=")([A-Z]+)\d+"/g, `$1$2${newRowNum}"`);

  // Corregir estilo s="N" de cada celda según alternado
  rowXml = rowXml.replace(/<c\s+r="([A-Z]+)\d+"([^>]*)>/g, (match, col, attrs) => {
    const targetStyle = styleMap[col];
    if (targetStyle === null || targetStyle === undefined) return match;
    // Reemplazar o agregar s="N"
    if (/\bs="\d+"/.test(attrs)) {
      attrs = attrs.replace(/\bs="\d+"/, `s="${targetStyle}"`);
    } else {
      attrs = ` s="${targetStyle}"` + attrs;
    }
    return `<c r="${col}${newRowNum}"${attrs}>`;
  });

  return rowXml;
});

// Reconstruir sheetData
const allFixedRows = [...headerRows.map(m => m[0]), ...fixedRows].join('');
sheetXml = sheetXml.replace(/<sheetData>[\s\S]*?<\/sheetData>/, `<sheetData>${allFixedRows}</sheetData>`);

zip.file(sheetPath, sheetXml);

const outBuf = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE' });
const b64    = outBuf.toString('base64');

const usuario     = (fromAddress || '').split('@')[0].toLowerCase();
const nitIps      = validRows[0]?.['NIT_DE_LA_IPS'] || 'SIN_NIT';
const fechaUTC    = json.receivedDateTime ? new Date(json.receivedDateTime) : new Date();
const offsetMs    = -5 * 60 * 60 * 1000;
const fechaCorreo = new Date(fechaUTC.getTime() + offsetMs);
const AAAA        = fechaCorreo.getUTCFullYear().toString();
const MM          = String(fechaCorreo.getUTCMonth() + 1).padStart(2, '0');
const DD          = String(fechaCorreo.getUTCDate()).padStart(2, '0');
const horas24     = fechaCorreo.getUTCHours();
const minutos     = String(fechaCorreo.getUTCMinutes()).padStart(2, '0');
const ampm        = horas24 >= 12 ? 'pm' : 'am';
const horas12     = horas24 % 12 || 12;
const outputName  = `${AAAA}_${MM}_${DD}_${horas12}_${minutos}_${ampm}_${nitIps}_${usuario}_${xlsxName}`;

const onedriveFolder = `/Cohortes/SaludMental/${yyyy}/${mm}`;
const onedrivePath   = `${onedriveFolder}/${outputName}`;

return [{
  json: { ...json, outputName, onedriveFolder, onedrivePath, nitIps},
  binary: {
    ...binary,
    validXlsx: {
      data:          b64,
      mimeType:      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName:      outputName,
      fileExtension: 'xlsx'
    }
  }
}];

const xlsx = require('xlsx');

const items   = $input.all();
const item    = items[0];
const json    = item?.json   || {};
const binary  = item?.binary || {};
const xlsxKey = json.xlsxKey;

if (!xlsxKey) {
  return [{ json: { ...json, tokenValido: false, xlsxKey: null }, binary }];
}

if (!binary[xlsxKey]) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: 'No se encontró el archivo Excel en los adjuntos.' },
    binary
  }];
}

let workbook;
try {
  const buf = Buffer.from(binary[xlsxKey].data, 'base64');
  workbook  = xlsx.read(buf, { type: 'buffer', cellDates: true });
} catch(e) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: `El archivo no es un Excel válido: ${e.message}` },
    binary
  }];
}

// Verificar hoja _META y token
if (!workbook.SheetNames.includes('_META')) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: 'El archivo no es la plantilla oficial (falta hoja _META).' },
    binary
  }];
}

const metaSheet = workbook.Sheets['_META'];
const token     = metaSheet['A1'] ? String(metaSheet['A1'].v).trim() : '';
const cohorte   = metaSheet['A2'] ? String(metaSheet['A2'].v).trim() : '';

if (token !== 'SM_v1.0' || cohorte !== 'SALUD_MENTAL') {
  return [{
    json: {
      ...json,
      tokenValido:   false,
      motivoRechazo: `Token inválido (encontrado: "${token}" / "${cohorte}"). Use la plantilla oficial.`
    },
    binary
  }];
}

// Verificar hoja de datos
const HOJA = 'SEGUIMIENTO_SM';
if (!workbook.SheetNames.includes(HOJA)) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: `No se encontró la hoja "${HOJA}". Use la plantilla oficial.` },
    binary
  }];
}

const dataSheet = workbook.Sheets[HOJA];

// Leer todas las filas en crudo para procesar encabezados manualmente
const rawRows = xlsx.utils.sheet_to_json(dataSheet, { defval: null, header: 1, range: 2 });

if (rawRows.length < 2) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: 'La hoja SEGUIMIENTO_SM no contiene datos.' },
    binary
  }];
}

// Limpiar encabezados: quitar \n, ★, espacios extra → NOMBRE_LIMPIO
const headersLimpios = (rawRows[0] || []).map(h =>
  String(h || '')
    .replace(/\n/g, ' ')
    .replace(/★/g, '')
    .replace(/[^a-zA-ZáéíóúÁÉÍÓÚñÑüÜ0-9\s]/g, '')
    .replace(/\s+/g, '_')
    .trim()
    .toUpperCase()
    .replace(/_+$/g, '')
);

// Reconstruir rows con headers limpios, ignorar filas completamente vacías
const rows = rawRows.slice(1).map(fila => {
  const obj = {};
  headersLimpios.forEach((h, i) => { obj[h] = fila[i] ?? null; });
  return obj;
}).filter(r => Object.values(r).some(v => v !== null));

if (rows.length === 0) {
  return [{
    json: { ...json, tokenValido: false, motivoRechazo: 'La hoja SEGUIMIENTO_SM no contiene datos.' },
    binary
  }];
}

// Verificar columnas obligatorias con nombres limpios
const COLUMNAS_REQUERIDAS = [
  'FECHA_DE_REPORTE',
  'NIT_DE_LA_IPS',
  'CÓDIGO_DE_HABILITACIÓN',
  'TIPO_DE_DOCUMENTO',
  'NÚMERO_DE_DOCUMENTO',
  'PRIMER_NOMBRE',
  'PRIMER_APELLIDO',
  'DIRECCIÓN_DE_RESIDENCIA',
  'TELÉFONO_CELULAR_1',
  'ESCOLARIDAD',
  'OCUPACIÓN',
  'CLASIFICACIÓN_DE_CASO',
  'CIE10_PRINCIPAL',
  'FECHA_DE_DIAGNÓSTICO'
];

const headers   = Object.keys(rows[0] || {});
const faltantes = COLUMNAS_REQUERIDAS.filter(c => !headers.includes(c));

if (faltantes.length > 0) {
  return [{
    json: {
      ...json,
      tokenValido:      false,
      motivoRechazo:    `Columnas obligatorias faltantes: ${faltantes.join(', ')}.`,
      DEBUG_headers:    headers.slice(0, 20)
    },
    binary
  }];
}

return [{
  json: {
    emailId:     json.emailId,
    fromAddress: json.fromAddress,
    fromName:    json.fromName,
    subject:     json.subject,
    xlsxKey:     json.xlsxKey,
    xlsxName:    json.xlsxName,
    pdfKeys:     json.pdfKeys,
    hasPdfs:     json.hasPdfs,
    yyyy:        json.yyyy,
    mm:          json.mm,
    fechaCargue: json.fechaCargue,
    tokenValido: true,
    rowCount:    rows.length,
    rows:        rows,
    headers:     headersLimpios
  },
  binary
}];

const items = $input.all();
const item  = items[0] || {};
const json  = item.json || {};

const rows = Array.isArray(json.rows) ? json.rows : [];

// ---------- Helpers ----------
const DATE_REGEX = /^\d{4}-\d{2}-\d{2}$/;

const endOfDay = (d) => {
  const x = new Date(d);
  x.setHours(23, 59, 59, 999);
  return x;
};

const parseYMD = (s) => {
  if (!s || !DATE_REGEX.test(String(s).trim())) return null;
  const [y, m, d] = String(s).trim().split('-').map(n => parseInt(n, 10));
  const dt = new Date(y, m - 1, d, 0, 0, 0, 0);
  return isNaN(dt.getTime()) ? null : dt;
};

const normStr = (v) => (v === null || v === undefined) ? '' : String(v).trim();

// ✅ NUEVO: normaliza ISO datetime (2026-05-12T00:00:00.000Z) → YYYY-MM-DD
const normalizeFecha = (v) => {
  const s = normStr(v);
  const match = s.match(/^(\d{4}-\d{2}-\d{2})(?:T.*)?$/);
  return match ? match[1] : s;
};

const validarFecha = (val, campo, errors, { noFutura = false, maxDate = null, noAnteriorA = null } = {}) => {
  const s = normStr(val);
  if (!s) return;

  if (!DATE_REGEX.test(s)) {
    errors.push(`${campo}: formato inválido ("${s}"), debe ser AAAA-MM-DD`);
    return;
  }

  const d = parseYMD(s);
  if (!d) {
    errors.push(`${campo}: fecha inválida "${s}"`);
    return;
  }

  if (noFutura && maxDate && d > maxDate) {
    errors.push(`${campo}: no puede ser posterior a la fecha de cargue`);
  }

  if (noAnteriorA && d < noAnteriorA) {
    errors.push(`${campo}: fecha (${s}) no puede ser anterior a FECHA_INGRESO_AL_PROGRAMA`);
  }
};

const fechaCargueStr = normStr(json.fechaCargue);
const maxNoFutura = endOfDay(parseYMD(fechaCargueStr) || new Date());

// ---------- Constantes ----------
const TIPOS_DOC_VALIDOS = ['RC','TI','CC','CE','PA','MS','AS','CD','SC','PE','PT','CN'];

const FECHAS_ATENCION = [
  'ATENCIÓN_1_PSIQUIATRÍA','ATENCIÓN_2_PSIQUIATRÍA','ATENCIÓN_3_PSIQUIATRÍA',
  'ATENCIÓN_4_PSIQUIATRÍA','ATENCIÓN_5_PSIQUIATRÍA','ATENCIÓN_6_PSIQUIATRÍA',
  'ATENCIÓN_7_PSIQUIATRÍA','ATENCIÓN_8_PSIQUIATRÍA',
  'ATENCIÓN_1_PSIQ_INFANTIL','ATENCIÓN_2_PSIQ_INFANTIL','ATENCIÓN_3_PSIQ_INFANTIL',
  'ATENCIÓN_4_PSIQ_INFANTIL','ATENCIÓN_5_PSIQ_INFANTIL','ATENCIÓN_6_PSIQ_INFANTIL',
  'ATENCIÓN_1_TRABAJO_SOCIAL','ATENCIÓN_2_TRABAJO_SOCIAL','ATENCIÓN_3_TRABAJO_SOCIAL',
  'ATENCIÓN_4_TRABAJO_SOCIAL','ATENCIÓN_5_TRABAJO_SOCIAL',
  'ATENCIÓN_1_MED_EXPERTO','ATENCIÓN_2_MED_EXPERTO','ATENCIÓN_3_MED_EXPERTO',
  'ATENCIÓN_4_MED_EXPERTO','ATENCIÓN_5_MED_EXPERTO',
  'ATENCIÓN_1_TERAP_OCUPACIONAL','ATENCIÓN_2_TERAP_OCUPACIONAL','ATENCIÓN_3_TERAP_OCUPACIONAL',
  'ATENCIÓN_1_NEUROPSICOLOGÍA','ATENCIÓN_2_NEUROPSICOLOGÍA','ATENCIÓN_3_NEUROPSICOLOGÍA',
  'ATENCIÓN_1_VISITA_DOMICILIARIA','ATENCIÓN_2_VISITA_DOMICILIARIA',
  'FECHA_UNIDAD_DE_ANÁLISIS_INTEGRAL'
];

const OBLIGATORIOS = [
  'FECHA_DE_REPORTE',
  'NIT_DE_LA_IPS',
  'CÓDIGO_DE_HABILITACIÓN',
  'TIPO_DE_DOCUMENTO',
  'NÚMERO_DE_DOCUMENTO',
  'PRIMER_NOMBRE',
  'PRIMER_APELLIDO',
  'DIRECCIÓN_DE_RESIDENCIA',
  'TELÉFONO_CELULAR_1',
  'ESCOLARIDAD',
  'OCUPACIÓN',
  'CLASIFICACIÓN_DE_CASO',
  'CIE10_PRINCIPAL',
  'FECHA_DE_DIAGNÓSTICO'
];

// ---------- Proceso ----------
const seen        = new Set();
const validRows   = [];
const invalidRows = [];

rows.forEach((row, idx) => {
  const errors = [];
  const rowNum = idx + 4;

  // Campos obligatorios
  for (const f of OBLIGATORIOS) {
    if (!normStr(row?.[f])) errors.push(`Campo obligatorio vacío: ${f}`);
  }

  // ✅ FECHA_DE_REPORTE (normalizada antes de validar)
  validarFecha(
    normalizeFecha(row?.['FECHA_DE_REPORTE']),
    'FECHA_DE_REPORTE',
    errors,
    { noFutura: true, maxDate: maxNoFutura }
  );

  // NIT: 9 dígitos
  const nitRaw = normStr(row?.['NIT_DE_LA_IPS']);
  if (nitRaw) {
    const nit = nitRaw.replace(/\D/g, '');
    if (nit.length !== 9) errors.push(`NIT_DE_LA_IPS: debe tener 9 dígitos (encontrado: ${nit.length})`);
  }

  // CÓDIGO HABILITACIÓN: 12 dígitos
  const habRaw = normStr(row?.['CÓDIGO_DE_HABILITACIÓN']);
  if (habRaw) {
    const cod = habRaw.replace(/\D/g, '');
    if (cod.length !== 12) errors.push(`CÓDIGO_DE_HABILITACIÓN: debe tener 12 dígitos (encontrado: ${cod.length})`);
  }

  // TIPO_DE_DOCUMENTO: lista cerrada
  const tdRaw = normStr(row?.['TIPO_DE_DOCUMENTO']);
  if (tdRaw) {
    const td = tdRaw.toUpperCase();
    if (!TIPOS_DOC_VALIDOS.includes(td)) {
      errors.push(`TIPO_DE_DOCUMENTO: valor "${td}" no válido. Opciones: ${TIPOS_DOC_VALIDOS.join(', ')}`);
    }
  }

  // NÚMERO_DE_DOCUMENTO: máx 20 chars
  const ndRaw = normStr(row?.['NÚMERO_DE_DOCUMENTO']);
  if (ndRaw && ndRaw.length > 20) errors.push('NÚMERO_DE_DOCUMENTO: excede 20 caracteres');

  // TELÉFONOS: 10 dígitos
  for (const tel of ['TELÉFONO_CELULAR_1','TELÉFONO_CELULAR_2']) {
    const telRaw = normStr(row?.[tel]);
    if (telRaw) {
      const t = telRaw.replace(/\D/g, '');
      if (t.length !== 10) errors.push(`${tel}: debe tener 10 dígitos (encontrado: ${t.length})`);
    }
  }

  // ESCOLARIDAD y OCUPACIÓN: 1-10
  for (const camp of ['ESCOLARIDAD','OCUPACIÓN']) {
    const vRaw = normStr(row?.[camp]);
    if (vRaw) {
      const v = parseInt(vRaw, 10);
      if (Number.isNaN(v) || v < 1 || v > 10) {
        errors.push(`${camp}: debe ser un número entre 1 y 10 (encontrado: ${vRaw})`);
      }
    }
  }

  // CLASIFICACIÓN_DE_CASO: 1 o 2
  const ccRaw = normStr(row?.['CLASIFICACIÓN_DE_CASO']);
  if (ccRaw) {
    const cc = parseInt(ccRaw, 10);
    if (![1, 2].includes(cc)) {
      errors.push(`CLASIFICACIÓN_DE_CASO: debe ser 1 (incidente) o 2 (prevalente) (encontrado: ${ccRaw})`);
    }
  }

  // CIE10: 4 caracteres
  const cieRaw = normStr(row?.['CIE10_PRINCIPAL']);
  if (cieRaw && cieRaw.length !== 4) {
    errors.push(`CIE10_PRINCIPAL: debe tener 4 caracteres (encontrado: ${cieRaw.length})`);
  }

  // ✅ FECHA_DE_DIAGNÓSTICO (normalizada antes de validar)
  validarFecha(
    normalizeFecha(row?.['FECHA_DE_DIAGNÓSTICO']),
    'FECHA_DE_DIAGNÓSTICO',
    errors,
    { noFutura: true, maxDate: maxNoFutura }
  );

  // Listas cerradas opcionales
  const clinRaw = normStr(row?.['CLASIFICACIÓN_CLÍNICA']);
  if (clinRaw) {
    const v = clinRaw.toUpperCase();
    if (!['MENTAL','FARMACO','DUAL'].includes(v)) errors.push('CLASIFICACIÓN_CLÍNICA: debe ser MENTAL, FARMACO o DUAL');
  }

  const riesgoRaw = normStr(row?.['RIESGO_PATOLÓGICO']);
  if (riesgoRaw) {
    const v = riesgoRaw.toUpperCase();
    if (!['BAJO','MEDIO','ALTO'].includes(v)) errors.push('RIESGO_PATOLÓGICO: debe ser BAJO, MEDIO o ALTO');
  }

  const remRaw = normStr(row?.['REMITIDO_A']);
  if (remRaw) {
    const v = remRaw.toUpperCase();
    if (!['HOSPITAL DIA','HOSPITALIZACION'].includes(v)) errors.push('REMITIDO_A: debe ser HOSPITAL DIA u HOSPITALIZACION');
  }

  // ✅ Fechas de atención (normalizadas antes de validar)
  const fechaIngresoStr = normalizeFecha(row?.['FECHA_INGRESO_AL_PROGRAMA']);
  const fechaIngreso = parseYMD(fechaIngresoStr);

  for (const campo of FECHAS_ATENCION) {
    const val = normalizeFecha(row?.[campo]);
    if (val) {
      validarFecha(val, campo, errors, { noFutura: true, maxDate: maxNoFutura, noAnteriorA: fechaIngreso });
    }
  }

  // Duplicados
  const keyDoc   = normStr(row?.['NÚMERO_DE_DOCUMENTO']);
  const keyFecha = normalizeFecha(row?.['FECHA_DE_REPORTE']);
  const keyNit   = normStr(row?.['NIT_DE_LA_IPS']);

  if (keyDoc && keyFecha && keyNit) {
    const dupKey = `${keyDoc}|${keyFecha}|${keyNit}`;
    if (seen.has(dupKey)) {
      errors.push(`Registro duplicado (NÚMERO_DE_DOCUMENTO: ${keyDoc}, FECHA_DE_REPORTE: ${keyFecha})`);
    } else {
      seen.add(dupKey);
    }
  }

  if (errors.length === 0) {
    validRows.push({ ...row, _fila_origen: rowNum });
  } else {
    invalidRows.push({ fila: rowNum, errores: errors });
  }
});

return [{
  json: {
    emailId:      json.emailId,
    fromAddress:  json.fromAddress,
    fromName:     json.fromName,
    subject:      json.subject,
    xlsxKey:      json.xlsxKey,
    xlsxName:     json.xlsxName,
    pdfKeys:      json.pdfKeys,
    hasPdfs:      json.hasPdfs,
    yyyy:         json.yyyy,
    mm:           json.mm,
    fechaCargue:  json.fechaCargue,

    validRows,
    invalidRows,
    totalRows:    rows.length,
    validCount:   validRows.length,
    invalidCount: invalidRows.length,
    tieneValidos: validRows.length > 0
  },
  binary: item.binary || {}
}];

const JSZip = require('jszip');
const items  = $input.all();
const item   = items[0];
const json   = item?.json   || {};
const binary = item?.binary || {};

const { invalidRows, validRows, xlsxName, fechaCargue, xlsxKey } = json;

if (!invalidRows || invalidRows.length === 0) {
  return [{ json: { ...json, errorXlsx: null }, binary }];
}

const binEntry = binary[xlsxKey]
              || $('Validar Token y Estructura').item?.binary?.[xlsxKey]
              || null;

if (!binEntry?.data) {
  return [{ json: { ...json, errorXlsx: null, motivoSinBinario: 'Binario no disponible' }, binary }];
}

const filasInvalidas = new Set(invalidRows.map(r => r.fila));
const filasValidas   = new Set((validRows || []).map(r => r._fila_origen).filter(Boolean));

const buf = Buffer.from(binEntry.data, 'base64');
const zip  = await JSZip.loadAsync(buf);

const workbookXml = await zip.file('xl/workbook.xml').async('string');
const sheetMatch  = workbookXml.match(/name="SEGUIMIENTO_SM"[^>]*r:id="(rId\d+)"/);
const rId         = sheetMatch?.[1];
const relsXml     = await zip.file('xl/_rels/workbook.xml.rels').async('string');
const relMatch    = relsXml.match(new RegExp(`Id="${rId}"[^>]*Target="([^"]+)"`));
const sheetPath   = `xl/${relMatch?.[1]}`;

let sheetXml = await zip.file(sheetPath).async('string');

const allRows = [...sheetXml.matchAll(/<row\b[^>]*\sr="(\d+)"[^>]*>[\s\S]*?<\/row>/g)];

const DATA_START = 4;

const headerRows      = allRows.filter(m => parseInt(m[1]) < DATA_START);
const dataRows        = allRows.filter(m => parseInt(m[1]) >= DATA_START);
const invalidDataRows = dataRows.filter(m => filasInvalidas.has(parseInt(m[1])));

// Filas vacías = ni inválidas ni válidas (filas de formato debajo de los datos)
const emptyRows = dataRows.filter(m => {
  const fila = parseInt(m[1]);
  return !filasInvalidas.has(fila) && !filasValidas.has(fila);
});

const getStyleMap = (rowXml) => {
  const map = {};
  const cells = [...rowXml.matchAll(/<c\s+r="([A-Z]+)\d+"([^>]*)>/g)];
  for (const cell of cells) {
    const col    = cell[1];
    const attrs  = cell[2];
    const sMatch = attrs.match(/\bs="(\d+)"/);
    map[col] = sMatch ? sMatch[1] : null;
  }
  return map;
};

const styleOdd  = dataRows[0] ? getStyleMap(dataRows[0][0]) : {};
const styleEven = dataRows[1] ? getStyleMap(dataRows[1][0]) : {};

const colToNum = col => col.split('').reduce((acc, c) => acc * 26 + c.charCodeAt(0) - 64, 0);
const numToCol = num => {
  let s = '';
  while (num > 0) { num--; s = String.fromCharCode(65 + num % 26) + s; num = Math.floor(num / 26); }
  return s;
};

const allColMatches = [...sheetXml.matchAll(/<c\s+r="([A-Z]+)\d+"/g)];
const maxColNum     = Math.max(...allColMatches.map(m => colToNum(m[1])));
const errorColLet   = numToCol(maxColNum + 1);
const lastDataCol   = numToCol(maxColNum);

const fixRowStyles = (rowXml, newRowNum, styleMap) => {
  rowXml = rowXml.replace(/(<row\b[^>]*\s)r="\d+"/, `$1r="${newRowNum}"`);
  rowXml = rowXml.replace(/(<c\s+r=")([A-Z]+)\d+"/g, `$1$2${newRowNum}"`);
  rowXml = rowXml.replace(/<c\s+r="([A-Z]+)\d+"([^>]*)>/g, (m, col, attrs) => {
    const targetStyle = styleMap[col];
    if (targetStyle === null || targetStyle === undefined) return m;
    if (/\bs="\d+"/.test(attrs)) {
      attrs = attrs.replace(/\bs="\d+"/, `s="${targetStyle}"`);
    } else {
      attrs = ` s="${targetStyle}"` + attrs;
    }
    return `<c r="${col}${newRowNum}"${attrs}>`;
  });
  return rowXml;
};

// Filas inválidas con columna de errores
const fixedRows = invalidDataRows.map((match, idx) => {
  const newRowNum    = DATA_START + idx;
  const esImpar      = idx % 2 === 0;
  const styleMap     = esImpar ? styleOdd : styleEven;
  const filaOriginal = parseInt(match[1]);

  let rowXml = fixRowStyles(match[0], newRowNum, styleMap);

  const errorEntry = invalidRows.find(r => r.fila === filaOriginal);
  const errorText  = errorEntry ? errorEntry.errores.join(' | ') : '';
  const errorStyle = styleMap[lastDataCol] ? ` s="${styleMap[lastDataCol]}"` : '';
  const errorCell  = `<c r="${errorColLet}${newRowNum}"${errorStyle} t="inlineStr"><is><t>${errorText}</t></is></c>`;
  rowXml = rowXml.replace(/<\/row>/, `${errorCell}</row>`);

  return rowXml;
});

// Filas vacías debajo con alternado correcto
const fixedEmptyRows = emptyRows.map((match, idx) => {
  const newRowNum = DATA_START + invalidDataRows.length + idx;
  const esImpar   = (invalidDataRows.length + idx) % 2 === 0;
  const styleMap  = esImpar ? styleOdd : styleEven;
  return fixRowStyles(match[0], newRowNum, styleMap);
});

// Encabezado ERRORES_ENCONTRADOS en fila 3
const headerRowIdx    = DATA_START - 1;
const fixedHeaderRows = headerRows.map(m => {
  if (parseInt(m[1]) !== headerRowIdx) return m[0];
  let rowXml = m[0];
  const errorHeaderCell = `<c r="${errorColLet}${headerRowIdx}" t="inlineStr"><is><t>ERRORES_ENCONTRADOS</t></is></c>`;
  rowXml = rowXml.replace(/<\/row>/, `${errorHeaderCell}</row>`);
  return rowXml;
});

const allFixedRows = [...fixedHeaderRows, ...fixedRows, ...fixedEmptyRows].join('');
sheetXml = sheetXml.replace(/<sheetData>[\s\S]*?<\/sheetData>/, `<sheetData>${allFixedRows}</sheetData>`);

zip.file(sheetPath, sheetXml);

const outBuf = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE' });
const b64    = outBuf.toString('base64');

const ts         = (fechaCargue || '').replace(/-/g, '');
const outputName = `ERRORES_${ts}_${xlsxName || 'reporte.xlsx'}`;

return [{
  json: {
    ...json,
    errorXlsx:    outputName,
    tieneErrores: true
  },
  binary: {
    ...binary,
    errorXlsx: {
      data:          b64,
      mimeType:      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName:      outputName,
      fileExtension: 'xlsx'
    }
  }
}];
